SELECT

FROM user_info
WHERE deleted = 0

    AND (
        account LIKE CONCAT('%', #{keyword}, '%')
        OR display_name LIKE CONCAT('%', #{keyword}, '%')
        OR email LIKE CONCAT('%', #{keyword}, '%')
        OR phone LIKE CONCAT('%', #{keyword}, '%')
    )


    AND user_status = #{userStatus}


    AND user_role = #{userRole}

ORDER BY create_time DESC, user_id DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(1) FROM user_info WHERE deleted = 0
AND ( account LIKE CONCAT('%', #{keyword}, '%') OR display_name LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') )
AND user_status = #{userStatus}
AND user_role = #{userRole}

mapper.update:
UPDATE user_info
SET
    point_balance = point_balance + #{pointDelta},
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND deleted = 0

UPDATE user_info
SET
    point_balance = point_balance - #{pointDelta},
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND deleted = 0
  AND point_balance >= #{pointDelta}
